const body = $input.first().json.body || $input.first().json;

if (!body.domain && !body.email && !body.company) {
  throw new Error('Provide at least one: domain, email, or company');
}

let domain = null;
if (body.domain) {
  domain = body.domain.replace(/^https?:\/\//, '').replace(/^www\./, '').split('/')[0].toLowerCase();
} else if (body.email) {
  domain = body.email.split('@')[1].toLowerCase();
}

const freeEmails = ['gmail.com','yahoo.com','hotmail.com','outlook.com','mail.ru','yandex.ru','protonmail.com'];
if (domain && freeEmails.includes(domain)) {
  domain = null;
}

return [{ json: {
  research_id: 'RES-' + Date.now(),
  input_domain: domain,
  input_company: body.company || null,
  input_email: body.email || null,
  input_context: body.context || null,
  has_domain: !!domain,
  started_at: new Date().toISOString()
}}];

const input = $('2. Parse Input').first().json;
const mxRaw = $('3. DNS MX Lookup').first().json;
const txtRaw = $('4. DNS TXT Lookup').first().json;
const aRaw = $('5. DNS A Lookup').first().json;

const mxRecords = [];
let emailProvider = 'unknown';
try {
  const answers = mxRaw.Answer || [];
  answers.forEach(a => {
    const mx = (a.data || '').toLowerCase();
    mxRecords.push(mx);
    if (mx.includes('google') || mx.includes('gmail')) emailProvider = 'Google Workspace';
    else if (mx.includes('outlook') || mx.includes('microsoft')) emailProvider = 'Microsoft 365';
    else if (mx.includes('zoho')) emailProvider = 'Zoho Mail';
    else if (mx.includes('yandex')) emailProvider = 'Yandex Mail';
    else if (mx.includes('protonmail')) emailProvider = 'ProtonMail';
    else if (mx.includes('mimecast')) emailProvider = 'Mimecast (Enterprise)';
    else if (mx.includes('barracuda')) emailProvider = 'Barracuda (Enterprise)';
  });
} catch(e) {}

const txtRecords = [];
const detectedServices = [];
try {
  const answers = txtRaw.Answer || [];
  answers.forEach(a => {
    const txt = (a.data || '').toLowerCase();
    txtRecords.push(txt);
    if (txt.includes('v=spf1')) detectedServices.push('SPF');
    if (txt.includes('google-site-verification')) detectedServices.push('Google Search Console');
    if (txt.includes('facebook-domain-verification')) detectedServices.push('Facebook Business');
    if (txt.includes('docusign')) detectedServices.push('DocuSign');
    if (txt.includes('hubspot')) detectedServices.push('HubSpot');
    if (txt.includes('salesforce')) detectedServices.push('Salesforce');
    if (txt.includes('zendesk')) detectedServices.push('Zendesk');
    if (txt.includes('atlassian')) detectedServices.push('Atlassian');
    if (txt.includes('stripe')) detectedServices.push('Stripe');
    if (txt.includes('shopify')) detectedServices.push('Shopify');
    if (txt.includes('mailchimp') || txt.includes('mandrill')) detectedServices.push('Mailchimp');
    if (txt.includes('sendgrid')) detectedServices.push('SendGrid');
    if (txt.includes('ms=ms')) detectedServices.push('Microsoft Verified');
    if (txt.includes('apple-domain-verification')) detectedServices.push('Apple Business');
    if (txt.includes('amazonses')) detectedServices.push('Amazon SES');
    if (txt.includes('intercom')) detectedServices.push('Intercom');
  });
} catch(e) {}

const ipAddresses = [];
let hostingProvider = 'unknown';
try {
  const answers = aRaw.Answer || [];
  answers.forEach(a => {
    const ip = a.data || '';
    ipAddresses.push(ip);
    if (ip.startsWith('104.') || ip.startsWith('172.67') || ip.startsWith('173.245')) hostingProvider = 'Cloudflare';
    else if (ip.startsWith('13.') || ip.startsWith('52.') || ip.startsWith('54.')) hostingProvider = 'AWS';
    else if (ip.startsWith('34.') || ip.startsWith('35.')) hostingProvider = 'Google Cloud';
    else if (ip.startsWith('40.') || ip.startsWith('20.')) hostingProvider = 'Microsoft Azure';
    else if (ip.startsWith('188.114') || ip.startsWith('104.16')) hostingProvider = 'Cloudflare';
    else if (ip.startsWith('76.76')) hostingProvider = 'Vercel';
    else if (ip.startsWith('185.199')) hostingProvider = 'GitHub Pages';
    else if (ip.startsWith('151.101')) hostingProvider = 'Fastly CDN';
  });
} catch(e) {}

let techScore = 0;
if (emailProvider !== 'unknown') techScore += 15;
if (emailProvider.includes('Enterprise')) techScore += 10;
if (detectedServices.length >= 5) techScore += 25;
else if (detectedServices.length >= 3) techScore += 15;
else if (detectedServices.length >= 1) techScore += 8;
if (hostingProvider === 'AWS' || hostingProvider === 'Google Cloud') techScore += 15;
else if (hostingProvider === 'Cloudflare') techScore += 10;
if (detectedServices.includes('HubSpot') || detectedServices.includes('Salesforce')) techScore += 10;
if (detectedServices.includes('Stripe') || detectedServices.includes('Shopify')) techScore += 10;

let techLevel = 'basic';
if (techScore >= 50) techLevel = 'enterprise';
else if (techScore >= 30) techLevel = 'advanced';
else if (techScore >= 15) techLevel = 'intermediate';

return [{ json: {
  ...input,
  dns_data: {
    mx_records: mxRecords,
    txt_records_count: txtRecords.length,
    ip_addresses: ipAddresses,
    email_provider: emailProvider,
    hosting_provider: hostingProvider,
    detected_services: [...new Set(detectedServices)],
    services_count: [...new Set(detectedServices)].length
  },
  tech_assessment: { score: techScore, level: techLevel }
}}];

const prevData = $('6. Analyze Tech Stack').first().json;
const response = $input.first().json;

let html = '';
if (typeof response === 'string') html = response;
else if (response.data) html = response.data;
else html = JSON.stringify(response).slice(0, 5000);

const getMetaContent = (html, name) => {
  const patterns = [
    new RegExp('<meta[^>]*name=["\']' + name + '["\'][^>]*content=["\']([^"\']*)["\'\]', 'i'),
    new RegExp('<meta[^>]*property=["\']' + name + '["\'][^>]*content=["\']([^"\']*)["\'\]', 'i')
  ];
  for (const p of patterns) {
    const m = html.match(p);
    if (m) return m[1].trim();
  }
  return null;
};

const titleMatch = html.match(/<title[^>]*>([^<]*)<\/title>/i);
const title = titleMatch ? titleMatch[1].trim() : null;
const description = getMetaContent(html, 'description');
const ogTitle = getMetaContent(html, 'og:title');
const ogDesc = getMetaContent(html, 'og:description');

const htmlLower = html.toLowerCase();
const webTech = [];
if (htmlLower.includes('wp-content') || htmlLower.includes('wordpress')) webTech.push('WordPress');
if (htmlLower.includes('shopify')) webTech.push('Shopify');
if (htmlLower.includes('wix.com')) webTech.push('Wix');
if (htmlLower.includes('squarespace')) webTech.push('Squarespace');
if (htmlLower.includes('react')) webTech.push('React');
if (htmlLower.includes('_next')) webTech.push('Next.js');
if (htmlLower.includes('vue')) webTech.push('Vue.js');
if (htmlLower.includes('angular')) webTech.push('Angular');
if (htmlLower.includes('bootstrap')) webTech.push('Bootstrap');
if (htmlLower.includes('tailwind')) webTech.push('Tailwind CSS');
if (htmlLower.includes('googletagmanager')) webTech.push('Google Tag Manager');
if (htmlLower.includes('google-analytics') || htmlLower.includes('gtag')) webTech.push('Google Analytics');
if (htmlLower.includes('hotjar')) webTech.push('Hotjar');
if (htmlLower.includes('intercom')) webTech.push('Intercom');
if (htmlLower.includes('hubspot')) webTech.push('HubSpot');
if (htmlLower.includes('zendesk')) webTech.push('Zendesk');
if (htmlLower.includes('drift')) webTech.push('Drift');
if (htmlLower.includes('crisp')) webTech.push('Crisp');
if (htmlLower.includes('segment')) webTech.push('Segment');
if (htmlLower.includes('stripe')) webTech.push('Stripe');
if (htmlLower.includes('recaptcha')) webTech.push('reCAPTCHA');
if (htmlLower.includes('cloudflare')) webTech.push('Cloudflare');

return [{ json: {
  ...prevData,
  website: {
    title: title || ogTitle,
    description: description || ogDesc,
    detected_web_tech: [...new Set(webTech)],
    web_tech_count: [...new Set(webTech)].length,
    page_loaded: html.length > 100
  }
}}];

const d = $input.first().json;

const allTech = [
  ...d.dns_data.detected_services,
  ...d.website.detected_web_tech,
  d.dns_data.email_provider !== 'unknown' ? d.dns_data.email_provider : null,
  d.dns_data.hosting_provider !== 'unknown' ? d.dns_data.hosting_provider + ' (hosting)' : null
].filter(Boolean);

const uniqueTech = [...new Set(allTech)];

let updatedScore = d.tech_assessment.score;
if (d.website.web_tech_count >= 3) updatedScore += 15;
else if (d.website.web_tech_count >= 1) updatedScore += 8;
if (d.website.page_loaded) updatedScore += 5;

let updatedLevel = 'basic';
if (updatedScore >= 60) updatedLevel = 'enterprise';
else if (updatedScore >= 35) updatedLevel = 'advanced';
else if (updatedScore >= 18) updatedLevel = 'intermediate';

const prompt = 'You are a B2B company research analyst. Based on the technical data below, create a company profile. Respond ONLY with valid JSON, no markdown:\n' +
  '{"company_summary": "2-3 sentences", "estimated_size": "startup|smb|mid_market|enterprise", "estimated_employees": "range", "likely_industry": "specific industry", "tech_maturity": "low|medium|high", "budget_indicator": "bootstrapped|funded|enterprise_budget", "sales_approach": "1 sentence", "key_insight": "most interesting finding"}\n\n' +
  'Data:\n' +
  'Domain: ' + d.input_domain + '\n' +
  'Website title: ' + (d.website.title || 'N/A') + '\n' +
  'Description: ' + (d.website.description || 'N/A') + '\n' +
  'Email: ' + d.dns_data.email_provider + '\n' +
  'Hosting: ' + d.dns_data.hosting_provider + '\n' +
  'Tech stack: ' + uniqueTech.join(', ') + '\n' +
  'Tech score: ' + updatedScore + '/100 (' + updatedLevel + ')\n' +
  'Total services: ' + uniqueTech.length + '\n' +
  (d.input_company ? 'Company name: ' + d.input_company + '\n' : '') +
  (d.input_context ? 'Context: ' + d.input_context + '\n' : '');

return [{ json: {
  ...d,
  all_tech: uniqueTech,
  tech_assessment: { score: updatedScore, level: updatedLevel },
  ai_prompt: prompt
}}];

