parameters.jsCode:
const data = $('9. Merge & Build Prompt').first().json;
const raw = $input.first().json;

let profile = {
  company_summary: 'AI profiling unavailable',
  estimated_size: 'unknown',
  estimated_employees: 'unknown',
  likely_industry: 'unknown',
  tech_maturity: 'unknown',
  budget_indicator: 'unknown',
  sales_approach: 'Standard outreach',
  key_insight: 'No AI insight available'
};

try {
  const content = raw.choices[0].message.content;
  const match = content.match(/\{[\s\S]*\}/);
  if (match) profile = JSON.parse(match[0]);
} catch(e) {}

return [{ json: { ...data, ai_profile: profile } }];

